final:
module RefModule(D,CLK,RSTB,Q,QN);input D;
 input CLK;
 input RSTB;
 output Q;
 output QN;

 reg obf_Qtemp;

 always @(posedge CLK or negedge RSTB) begin
   if (~RSTB) begin
     obf_Qtemp <= 1'b0;
   end else begin
     obf_Qtemp <= D;
   end
 end

 assign QN = ~obf_Qtemp;
 assign Q = obf_Qtemp;

endmodule
